  id: string;
  articleSlug: string;
  noosphereArticleId: string | null;
  findingId: string;
  summary: string;
  body: string;
  status: string;
  reviewerConfig: string;
  createdAt: Date;
  publishedAt: Date | null;
  dismissedAt: Date | null;
  dismissedReason: string;
}): AddendumRecord {
