            {p.openQuestionsAdjacent.map((x) => (
              <li key={x}>{x}</li>
            ))}
          </ul>
        </section>
      ) : null}

      {p.voiceComparisons?.length ? (
        <section className="public-section">
          <h2>Tracked voices (comparison)</h2>
          <ul>
            {p.voiceComparisons.map((v) => (
              <li key={`${v.voice}:${v.stance}`}>
                <strong>{v.voice}:</strong> {v.stance}
              </li>
            ))}
          </ul>
        </section>
      ) : null}

      {responses.length ? (
        <section className="public-section">
          <h2>Public responses</h2>
          <ul className="public-response-list">
            {responses.map((r) => (
              <li key={r.id} className="public-card">
                <div className="public-muted mono">
                  {r.kind} · {r.status}
                  {r.pseudonymous ? " · pseudonymous (email verified)" : ""} · {r.createdAt.slice(0, 10)}
                </div>
                <p>{r.body}</p>
                {r.citationUrl ? (
                  <p className="public-muted">
                    Citation:{" "}
                    <a href={r.citationUrl} rel="noreferrer">
                      {r.citationUrl}
                    </a>
                  </p>
                ) : null}
              </li>
            ))}
          </ul>
        </section>
      ) : null}

      <PrintEndnotes sources={buildPrintEndnotes(p)} />

      {bottomSlot}
    </main>
  );
}

/**
 * Convert the public payload's citations + article-citation manifest
 * into ordered endnote rows for the print stylesheet.
 *
 * Numbering is stable: it follows the manifest order so a reader who
 * saw "[1]" inline finds note 1 here. Internal-only sources have no
 * `publicUrl`; we still list them, but the URL field is omitted so a
 * private link cannot leak into a printed document.
 */
function buildPrintEndnotes(
  p: PublishedConclusion["payload"],
): PrintEndnoteSource[] {
  const out: PrintEndnoteSource[] = [];
  const article = p.article;
  if (article && article.citations.length) {
    for (const c of article.citations) {
      out.push({
        label: c.label,
        title:
          c.sourceConclusionText?.trim() ||
          c.quotedSpan?.trim() ||
          c.sourceId ||
          c.label,
        kind: citationKindLabel(c.sourceKind),
        url: c.publicUrl ?? null,
      });
    }
  }
  // Note: the APA/BibTeX/RIS blocks in `p.citations` are deliberately
  // not echoed into the printed endnotes. They're a copy-paste tool
  // for the screen reader, not per-source notes — repeating them here
  // would clutter the printed page. Readers who want a citation block
  // are expected to grab it from the live page.
  return out;
}

function ArticleSourceList({
  citations,
}: {
  citations: NonNullable<PublishedConclusion["payload"]["article"]>["citations"];
}) {
  if (!citations.length) return null;

  return (
    <section aria-labelledby="article-sources-title" className="public-section">
      <h2 id="article-sources-title">Sources</h2>
      <ol className="firm-source-list">
        {citations.map((citation) => {
          const sourceText = citation.sourceConclusionText?.trim() || null;
          const href = sourceText ? citation.publicUrl : null;
          const sourceKind = citationKindLabel(citation.sourceKind);
          return (
            <li className="firm-source-row" key={`${citation.label}:${citation.sourceKind}:${citation.sourceId}`}>
              {sourceText ? (
                <>
                  {href ? (
                    <Link
                      href={href}
                      rel={isExternalHref(href) ? "noreferrer" : undefined}
                      target={isExternalHref(href) ? "_blank" : undefined}
                    >
                      {sourceText}
                    </Link>
                  ) : (
                    <span>{sourceText}</span>
                  )}
                  <small aria-hidden="true" className="mono">
                    {sourceKind}
                  </small>
                </>
              ) : (
                <span className="public-muted">Internal source recorded by the firm</span>
              )}
            </li>
          );
        })}
      </ol>
    </section>
  );
}

